def select_words(s, n):
    if not s:
        return []

    # Define vowels (both lowercase and uppercase)
    vowels = "aeiouAEIOU"

    # Split the string into words
    words = s.split()

    result = []

    for word in words:
        # Count consonants in the word
        consonant_count = 0
        for char in word:
            if char.isalpha() and char not in vowels:
                consonant_count += 1

        # If the word has exactly n consonants, add it to the result
        if consonant_count == n:
            result.append(word)

    return result
```

```python
def unique_digits(x):
    def has_no_even_digit(num):
        # Convert number to string to check each digit
        for digit_char in str(num):
            digit = int(digit_char)
            if digit % 2 == 0:  # if digit is even (0, 2, 4, 6, 8)
                return False
        return True

    # Filter numbers that have no even digits
    result = [num for num in x if has_no_even_digit(num)]

    # Return sorted list
    return sorted(result)
```

