from typing import List

def parse_music(music_string: str) -> List[int]:
    notes = music_string.split()
    result = []

    for note in notes:
        if note == 'o':
            result.append(4)  # whole note
        elif note == 'o|':
            result.append(2)  # half note
        elif note == '.|':
            result.append(1)  # quarter note

    return result
```

