def pluck(arr):
    if not arr:
        return []

    smallest_even = None
    smallest_index = -1

    for i, value in enumerate(arr):
        if value % 2 == 0:  # check if even
            if smallest_even is None or value < smallest_even:
                smallest_even = value
                smallest_index = i

    if smallest_even is None:
        return []

    return [smallest_even, smallest_index]
```

