def any_int(x, y, z):
    # Check if all numbers are integers
    if not (isinstance(x, int) or (isinstance(x, float) and x.is_integer())):
        return False
    if not (isinstance(y, int) or (isinstance(y, float) and y.is_integer())):
        return False
    if not (isinstance(z, int) or (isinstance(z, float) and z.is_integer())):
        return False

    # Convert to integers to handle float representations of integers
    x_int = int(x) if isinstance(x, float) else x
    y_int = int(y) if isinstance(y, float) else y
    z_int = int(z) if isinstance(z, float) else z

    # Check if one number equals the sum of the other two
    return (x_int == y_int + z_int) or (y_int == x_int + z_int) or (z_int == x_int + y_int)
```

```python
def any_int(x, y, z):
    # Check if all numbers are integers
    # We need to check if they are whole numbers (int or float that represents an integer)
    def is_integer(num):
        return isinstance(num, int) or (isinstance(num, float) and num.is_integer())

    if not (is_integer(x) and is_integer(y) and is_integer(z)):
        return False

    # Convert to int if they are floats representing integers
    x_int = int(x) if isinstance(x, float) else x
    y_int = int(y) if isinstance(y, float) else y
    z_int = int(z) if isinstance(z, float) else z

    # Check if one number equals the sum of the other two
    return (x_int == y_int + z_int) or (y_int == x_int + z_int) or (z_int == x_int + y_int)
```

