def choose_num(x, y):
    # Check if the range is valid (x should be <= y)
    if x > y:
        return -1

    # Start from the largest number in the range and work backwards
    # Find the largest even number in [x, y]
    for num in range(y, x - 1, -1):
        if num % 2 == 0:
            return num

    # If no even number found
    return -1
```

```python
def sum_squares(lst):
    total = 0
    for i, value in enumerate(lst):
        if i % 3 == 0:
            # index is multiple of 3: square the value
            total += value ** 2
        elif i % 4 == 0:
            # index is multiple of 4 but not multiple of 3: cube the value
            # Note: if i % 3 == 0 is false and i % 4 == 0 is true, then it's multiple of 4 but not 3
            total += value ** 3
        else:
            # not multiple of 3 or 4: add as is
            total += value
    return total
```

